#include "weights.h"

#include <stddef.h>
#include <stdint.h>
#include <stdio.h>
#include <string.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <fcntl.h>
#include <unistd.h>

static bool checked_mul_size(size_t a, size_t b, size_t *out) {
    if (out == NULL) {
        return false;
    }

    if (a != 0 && b > SIZE_MAX / a) {
        return false;
    }

    *out = a * b;
    return true;
}

static bool checked_add_size(size_t a, size_t b, size_t *out) {
    if (out == NULL) {
        return false;
    }

    if (b > SIZE_MAX - a) {
        return false;
    }

    *out = a + b;
    return true;
}

static bool add_tensor_bytes(size_t *total, size_t count) {
    size_t bytes;
    size_t next_total;

    if (!checked_mul_size(count, sizeof(float), &bytes)) {
        return false;
    }

    if (!checked_add_size(*total, bytes, &next_total)) {
        return false;
    }

    *total = next_total;
    return true;
}

static bool weights_core_size(const Config *config, size_t *out) {
    size_t total;
    size_t dim;
    size_t hidden_dim;
    size_t n_layers;
    size_t vocab_size;
    size_t seq_len;
    size_t head_size;
    size_t kv_dim;

    if (!config_is_valid(config) || out == NULL) {
        return false;
    }

    total = sizeof(Config);
    dim = (size_t)config->dim;
    hidden_dim = (size_t)config->hidden_dim;
    n_layers = (size_t)config->n_layers;
    vocab_size = (size_t)config->vocab_size;
    seq_len = (size_t)config->seq_len;
    head_size = (size_t)config_head_size(config);
    kv_dim = (size_t)config_kv_dim(config);

    if (!add_tensor_bytes(&total, vocab_size * dim) ||
        !add_tensor_bytes(&total, n_layers * dim) ||
        !add_tensor_bytes(&total, n_layers * dim * dim) ||
        !add_tensor_bytes(&total, n_layers * dim * kv_dim) ||
        !add_tensor_bytes(&total, n_layers * dim * kv_dim) ||
        !add_tensor_bytes(&total, n_layers * dim * dim) ||
        !add_tensor_bytes(&total, n_layers * dim) ||
        !add_tensor_bytes(&total, n_layers * hidden_dim * dim) ||
        !add_tensor_bytes(&total, n_layers * dim * hidden_dim) ||
        !add_tensor_bytes(&total, n_layers * hidden_dim * dim) ||
        !add_tensor_bytes(&total, dim) ||
        !add_tensor_bytes(&total, seq_len * head_size / 2) ||
        !add_tensor_bytes(&total, seq_len * head_size / 2)) {
        return false;
    }

    *out = total;
    return true;
}

static bool map_tensor(const float **tensor, const float **cursor, size_t count) {
    const float *start;

    if (tensor == NULL || cursor == NULL || *cursor == NULL) {
        return false;
    }

    start = *cursor;
    *tensor = start;
    *cursor = start + count;
    return true;
}

static bool weights_assign_pointers(TransformerWeights *weights, const Config *config) {
    const float *cursor;
    size_t dim;
    size_t hidden_dim;
    size_t n_layers;
    size_t vocab_size;
    size_t seq_len;
    size_t head_size;
    size_t kv_dim;
    size_t core_size;
    size_t classifier_bytes;

