#include <stdio.h>
#include <stdlib.h>

#include "llama.h"

static int print_usage(const char *argv0) {
    fprintf(stderr, "usage: %s <model.bin> [token] [position]\n", argv0);
    return 1;
}

static void print_logits_preview(const Transformer *transformer, int count) {
    int i;
    int limit = count;

    if (transformer->state.logits == NULL) {
        return;
    }

    if (limit > transformer->config.vocab_size) {
        limit = transformer->config.vocab_size;
    }

    puts("logits preview:");
    for (i = 0; i < limit; ++i) {
        printf("  logits[%d] = %.6f\n", i, transformer->state.logits[i]);
    }
}

int main(int argc, char **argv) {
    Transformer transformer;
    int token = 0;
    int position = 0;

    if (argc < 2 || argc > 4) {
        return print_usage(argv[0]);
    }

    if (argc >= 3) {
        token = atoi(argv[2]);
    }

    if (argc >= 4) {
        position = atoi(argv[3]);
    }

    if (!transformer_init(&transformer)) {
        fprintf(stderr, "failed to initialize transformer\n");
        return 1;
    }

    if (!transformer_load(&transformer, argv[1])) {
        fprintf(stderr, "failed to load model: %s\n", argv[1]);
        transformer_free(&transformer);
        return 1;
    }

    printf("loaded model: %s\n", argv[1]);
    config_print(&transformer.config, stdout);

    if (!transformer_forward(&transformer, token, position)) {
        fprintf(stderr, "forward failed for token=%d position=%d\n", token, position);
        transformer_free(&transformer);
        return 1;
    }

    printf("forward ok: token=%d position=%d\n", token, position);
    print_logits_preview(&transformer, 8);

    transformer_free(&transformer);

