+    coin = random_f32(&sampler->rng_state);
+    cdf = 0.0f;
+    for (i = 0; i < sampler->vocab_size; ++i) {
+        cdf += sampler->probabilities[i];
+        if (coin <= cdf) {
+            return i;
+        }
+    }
+
+    return sampler->vocab_size - 1;
+}

